import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../utils/api';
import { useCart } from '../context/CartContext';

const ProductPage = () => {
  const { id } = useParams();
  const [product, setProduct] = useState(null);
  const { addToCart } = useCart();
  const navigate = useNavigate();

  useEffect(() => {
    api.get(`/products/${id}`).then((res) => setProduct(res.data));
  }, [id]);

  if (!product) return (
    <p style={{ textAlign: 'center', marginTop: '40px' }}>Loading...</p>
  );

  return (
    <div style={{ padding: '40px', maxWidth: '800px', margin: '0 auto' }}>
      <button onClick={() => navigate(-1)} style={styles.back}>← Back</button>
      <div style={styles.container}>
        <img src={product.image} alt={product.name} style={styles.img} />
        <div style={{ flex: 1 }}>
          <h2>{product.name}</h2>
          <p style={{ color: '#888' }}>{product.category}</p>
          <p style={{ fontSize: '28px', fontWeight: 'bold', color: '#e94560' }}>
            ${product.price}
          </p>
          <p style={{ lineHeight: '1.6', color: '#444' }}>{product.description}</p>
          <p>In Stock: <strong>{product.stock}</strong></p>
          <button
            onClick={() => { addToCart(product); navigate('/cart'); }}
            style={styles.btn}
          >
            🛒 Add to Cart
          </button>
        </div>
      </div>
    </div>
  );
};

const styles = {
  back: { background: 'none', border: '1px solid #ccc', padding: '6px 14px', borderRadius: '6px', cursor: 'pointer', marginBottom: '20px' },
  container: { display: 'flex', gap: '30px', flexWrap: 'wrap' },
  img: { width: '320px', height: '300px', objectFit: 'cover', borderRadius: '10px' },
  btn: { marginTop: '20px', padding: '12px 28px', background: '#e94560', color: '#fff', border: 'none', borderRadius: '8px', fontSize: '16px', cursor: 'pointer' },
};

export default ProductPage;
